14a51dcd  function truncateHeadTail(text: string, linesPerSide: number): string {
fdcda396    const lines = text.split("\n");
ba438691    if (lines.length <= linesPerSide * 2) return text;
36cfe892    const head = lines.slice(0, linesPerSide).join("\n");
c7159375    const tail = lines.slice(-linesPerSide).join("\n");
8ab16a12    return `${head}\n…(truncated ${lines.length - linesPerSide * 2} lines)…\n${tail}`;
d10b36aa  }
